args.sparql:
SELECT ?person ?personLabel
WHERE {
  ?person wdt:P106 wd:Q4203130 ;  
          wdt:P21 wd:Q6581072 ;  
          wdt:P541 ?season .     
  ?season wdt:P177 wd:Q58455326 ;
          wdt:P585 ?seasonDate .
  FILTER (YEAR(?seasonDate) = 2019)
  ?teamWeek wdt:P166 ?person .    
  FILTER (CONTAINS(LCASE(STR(?teamWeek)), "nissan net points team of the week"))
}
GROUP BY ?person
HAVING (COUNT(?teamWeek) = 10)

SELECT ?person ?personLabel 
WHERE {
  ?person wdt:P106 wd:Q4203130 ;
          wdt:P21 wd:Q6581072 ;
          wdt:P541 ?season .
  ?season wdt:P177 wd:Q58455326 ;
          wdt:P585 ?seasonDate .
  FILTER (YEAR(?seasonDate) = 2019)

  ?teamWeek wdt:P166 ?person .
  ?teamWeek rdfs:label ?teamWeekLabel .
  FILTER (CONTAINS(LCASE(?teamWeekLabel), "nissan net points team of the week"))
}
GROUP BY ?person
HAVING (COUNT(?teamWeek) = 10)

SELECT ?person ?personLabel
WHERE {
  ?award rdfs:label ?awardLabel ;
         wdt:P585 ?awardDate .
  FILTER (CONTAINS(LCASE(?awardLabel), "nissan net points team of the week") &&
          YEAR(?awardDate) = 2019)
  ?award wdt:P166 ?person .
  ?person wdt:P21 wd:Q6581072 ;
          wdt:P106 wd:Q4203130 ;
          wdt:P122 wd:Q3410704
}
GROUP BY ?person
HAVING (COUNT(?award) = 10)

SELECT ?person ?personLabel
WHERE {
  ?award wdt:P177 wd:Q58455326 ;  
         rdfs:label ?awardLabel ;
         wdt:P585 ?awardDate ;
         wdt:P166 ?person .
  FILTER (CONTAINS(LCASE(?awardLabel), "nissan net points team of the week") &&
          YEAR(?awardDate) = 2019)
  ?person wdt:P21 wd:Q6581072 ;
          wdt:P106 wd:Q4203130 ;
          wdt:P122 wd:Q3410704
}
GROUP BY ?person
HAVING (COUNT(?award) = 10)
